#!/usr/bin/env python3
from __future__ import annotations

import argparse
import csv
import json
import re
import signal
import sys
import urllib.request
from datetime import datetime
from pathlib import Path
from typing import Any

ANALYZER_TIMEOUT_SEC = 15  # 单只股票分析超时秒数，超时则视为 unavailable

ROOT = Path(__file__).resolve().parents[1]
REPORT_DIR = ROOT / 'research' / 'reports'
DSA_ROOT = Path('/Users/ling/.openclaw/workspace/quant_projects/daily_stock_analysis')

# ── thresholds for analyzer_service veto ────────────────────────────────────
SENTIMENT_SCORE_MIN = 40          # below this → block
NEGATIVE_ADVICES = {"减仓", "卖出"}

# ── normalise helpers ───────────────────────────────────────────────────────
CODE_FIELDS = ['ts_code', 'ticker', 'symbol', 'code', 'stock_code']
SIDE_FIELDS = ['side', 'action', 'order_side', 'trade_side', 'signal_side']
BUY_VALUES = {'buy', 'open_buy', 'long', 'b'}


def normalize_symbol(symbol: str) -> str:
    s = str(symbol or '').strip().upper()
    if not s:
        return s
    s = s.replace('.', '')
    if re.fullmatch(r'\d{6}SH', s):
        return 'sh' + s[:6]
    if re.fullmatch(r'\d{6}SZ', s):
        return 'sz' + s[:6]
    if re.fullmatch(r'SH\d{6}', s):
        return 'sh' + s[2:]
    if re.fullmatch(r'SZ\d{6}', s):
        return 'sz' + s[2:]
    if re.fullmatch(r'\d{6}', s):
        return ('sh' if s.startswith('6') else 'sz') + s
    return s.lower()


def _ths_ts_code(symbol: str) -> str:
    """Convert symbol to THS/TDX format (e.g. 002920.SZ)."""
    s = str(symbol or '').strip().upper()
    s = s.replace('.', '').replace('SH', '').replace('SZ', '')
    if len(s) == 6:
        return ('SZ' if s.startswith(('0', '3')) else 'SH') + s
    # already in format
    return symbol.upper()


# ── unified fetcher (THS/TDX priority) ─────────────────────────────────────
def _get_unified_fetcher():
    """Return a configured DataFetcherManager with THS/TDX at highest priority."""
    if str(DSA_ROOT) not in sys.path:
        sys.path.insert(0, str(DSA_ROOT))
    from data_provider.base import DataFetcherManager
    from data_provider.efinance_fetcher import EfinanceFetcher
    from data_provider.akshare_fetcher import AkshareFetcher
    from data_provider.ths_market_fetcher import ThsMarketFetcher
    from data_provider.pytdx_fetcher import PytdxFetcher
    from data_provider.tushare_fetcher import TushareFetcher
    from data_provider.baostock_fetcher import BaostockFetcher

    fetchers = [
        ThsMarketFetcher(priority=0),    # 同花顺最高优先级
        PytdxFetcher(priority=1),       # 通达信次高
        EfinanceFetcher(priority=2),
        AkshareFetcher(priority=3),
        TushareFetcher(priority=4),
        BaostockFetcher(priority=5),
    ]
    return DataFetcherManager(fetchers=fetchers)


# ── quote (unified fetcher with THS/TDX priority, fallback to tencent) ──────
def fetch_quote(symbol: str) -> dict[str, Any]:
    # 方法1：尝试统一路由（THS → Pytdx → Efinance → AkShare）
    try:
        manager = _get_unified_fetcher()
        ts_code = _ths_ts_code(symbol)
        quote = manager.get_realtime_quote(ts_code)
        if quote is not None and quote.price is not None and quote.price > 0:
            return {
                'valid': True,
                'input_symbol': symbol,
                'market_symbol': ts_code,
                'name': getattr(quote, 'name', '') or '',
                'price': quote.price,
                'change_pct': quote.change_pct or 0.0,
                'source': 'unified_fetcher',
            }
    except Exception:
        pass

    # 方法2：降级到腾讯直连
    market_symbol = normalize_symbol(symbol)
    url = f'http://qt.gtimg.cn/q={market_symbol}'
    try:
        with urllib.request.urlopen(url, timeout=8) as resp:
            text = resp.read().decode('gbk', errors='ignore')
        m = re.match(r'v_\w+="(.*)";', text.strip())
        if not m:
            return {'valid': False, 'symbol': symbol, 'reason': 'parse_failed'}
        f = m.group(1).split('~')
        if len(f) < 48:
            return {'valid': False, 'symbol': symbol, 'reason': 'field_short'}
        return {
            'valid': True,
            'input_symbol': symbol,
            'market_symbol': market_symbol,
            'name': f[1] or '',
            'price': float(f[3] or 0),
            'change_pct': float(f[32] or 0),
            'source': 'tencent_fallback',
        }
    except Exception as e:
        return {'valid': False, 'symbol': symbol, 'reason': repr(e)}


# ── analyzer_service ────────────────────────────────────────────────────────
def _load_analyzer_service():
    """Lazy-import analyzer_service; return (module, error)."""
    if not (DSA_ROOT / 'analyzer_service.py').exists():
        return None, 'dsa_root_not_found'
    if str(DSA_ROOT) not in sys.path:
        sys.path.insert(0, str(DSA_ROOT))
    try:
        import importlib
        mod = importlib.import_module('analyzer_service')
        return mod, None
    except Exception as e:
        return None, repr(e)


def _timeout_handler(signum, frame):
    raise TimeoutError('analyzer_service timed out')


def fetch_analyzer_analysis(symbol: str) -> dict[str, Any]:
    """
    Call analyzer_service.analyze_stock with a per-stock timeout.
    Returns a dict with:
      - available: bool
      - sentiment_score: int | None
      - operation_advice: str | None
      - core_conclusion: str | None
      - error: str | None
    """
    mod, err = _load_analyzer_service()
    if err:
        return {'available': False, 'symbol': symbol, 'error': err}
    old_handler = signal.signal(signal.SIGALRM, _timeout_handler)
    signal.alarm(ANALYZER_TIMEOUT_SEC)
    try:
        result = mod.analyze_stock(symbol)
        signal.alarm(0)
        if result is None:
            return {'available': False, 'symbol': symbol, 'error': 'analyze_stock returned None'}
        return {
            'available': True,
            'symbol': symbol,
            'sentiment_score': getattr(result, 'sentiment_score', None),
            'operation_advice': getattr(result, 'operation_advice', None),
            'core_conclusion': getattr(result, 'core_conclusion', None) or '',
        }
    except TimeoutError:
        signal.alarm(0)
        return {'available': False, 'symbol': symbol, 'error': f'timeout_after_{ANALYZER_TIMEOUT_SEC}s'}
    except Exception as e:
        signal.alarm(0)
        return {'available': False, 'symbol': symbol, 'error': repr(e)}
    finally:
        signal.signal(signal.SIGALRM, old_handler)


def analyzer_veto(analysis: dict[str, Any]) -> tuple[bool, str]:
    """
    Returns (should_block, reason).
    """
    if not analysis.get('available'):
        return False, ''   # no data → don't block on analyzer basis
    score = analysis.get('sentiment_score')
    advice = analysis.get('operation_advice') or ''
    reasons = []
    if score is not None and int(score) < SENTIMENT_SCORE_MIN:
        reasons.append(f"sentiment_score {score} < {SENTIMENT_SCORE_MIN}")
    if advice in NEGATIVE_ADVICES:
        reasons.append(f"operation_advice '{advice}' in {NEGATIVE_ADVICES}")
    if reasons:
        return True, '; '.join(reasons)
    return False, ''


# ── csv reader ───────────────────────────────────────────────────────────────
def load_candidates_from_csv(path: Path) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    if not path.exists():
        return rows
    with path.open('r', encoding='utf-8', newline='') as f:
        reader = csv.DictReader(f)
        for row in reader:
            code = None
            for field in CODE_FIELDS:
                if row.get(field):
                    code = row[field]
                    break
            if not code:
                continue
            side = ''
            for field in SIDE_FIELDS:
                if row.get(field):
                    side = str(row[field]).strip().lower()
                    break
            if side and side not in BUY_VALUES:
                continue
            rows.append({'symbol': code, 'raw': row})
    return rows


# ── main ────────────────────────────────────────────────────────────────────
def main() -> None:
    ap = argparse.ArgumentParser(description='个股实时前置门禁 V2（增强：接入 analyzer_service）')
    ap.add_argument('--date', default=datetime.now().strftime('%Y%m%d'))
    ap.add_argument('--profile', required=True, choices=['defensive', 'balanced', 'aggressive'])
    ap.add_argument('--max-down-pct', type=float, default=-3.0)
    ap.add_argument('--use-analyzer', action='store_true',
                    help='调用 analyzer_service 进行情绪/建议审查（可能较慢）')
    ap.add_argument('--sentiment-min', type=int, default=SENTIMENT_SCORE_MIN,
                    help=f'情绪得分最低阈值（默认 {SENTIMENT_SCORE_MIN}）')
    args = ap.parse_args()

    csv_path = REPORT_DIR / f'paper_{args.profile}_merged_proposed_orders_{args.date}.csv'
    candidates = load_candidates_from_csv(csv_path)

    checked = []
    blocked = []
    passed = []
    analyzer_available = False

    for item in candidates:
        symbol = item['symbol']
        rec: dict[str, Any] = {'symbol': symbol}

        # Layer 1a: quote check
        q = fetch_quote(symbol)
        rec['quote'] = q
        if not q.get('valid'):
            rec['decision'] = 'block'
            rec['block_reason'] = f"quote_unavailable: {q.get('reason','')}"
            blocked.append(rec)
            checked.append(rec)
            continue

