#!/usr/bin/env python3
"""
盘中实时市场宽度（上涨家数比）- 多源兜底

数据源优先级（三源兜底）：
1. AkShare（东方财富实时）
2. eFinance（腾讯/新浪实时）
3. Tushare Pro（日线今日数据，降级兜底）

当 1+2 都被代理阻塞时，尝试 Tushare（已知在当前环境可用）。
"""
from __future__ import annotations

import json
import time
from pathlib import Path
from typing import Any

ROOT = Path(__file__).resolve().parents[1]


# ── 1. AkShare ─────────────────────────────────────────────────────────────
def fetch_from_akshare(max_retry: int = 2, sleep_sec: float = 1.5) -> dict[str, Any]:
    last_error = ""
    for attempt in range(1, max_retry + 1):
        try:
            import akshare as ak
            df = ak.stock_zh_a_spot_em()
            if df is None or df.empty:
                raise RuntimeError("stock_zh_a_a_spot_em returned empty")
            change_col = None
            for cand in ["涨跌幅", "涨跌幅%", "涨跌幅(%)"]:
                if cand in df.columns:
                    change_col = cand
                    break
            if change_col is None:
                raise RuntimeError(f"missing change column: {list(df.columns)}")
            changes = df[change_col].astype(str).str.replace('%', '', regex=False)
            changes = changes.replace({'-': None, 'None': None, 'nan': None}).astype(float).dropna()
            if changes.empty:
                raise RuntimeError("no valid change pct rows")
            up = int((changes > 0).sum())
            down = int((changes < 0).sum())
            flat = int((changes == 0).sum())
            total = int(len(changes))
            ratio = float(up / total) if total > 0 else None
            return {
                "available": True,
                "source": "akshare.stock_zh_a_spot_em",
                "up_count": up, "down_count": down, "flat_count": flat,
                "total_count": total, "up_ratio": ratio,
            }
        except Exception as e:
            last_error = repr(e)
            if attempt < max_retry:
                time.sleep(sleep_sec)
    return {"available": False, "source": "akshare.stock_zh_a_spot_em", "error": last_error}


# ── 2. eFinance ─────────────────────────────────────────────────────────────
def fetch_from_efinance() -> dict[str, Any]:
    try:
        import efinance as ef
        df = ef.stock.get_realtime_quotes()
        if df is None or df.empty:
            raise RuntimeError('efinance realtime quotes empty')
        change_col = None
        for cand in ['涨跌幅', '涨跌幅(%)']:
            if cand in df.columns:
                change_col = cand
                break
        if change_col is None:
            raise RuntimeError(f'missing change column: {list(df.columns)}')
        changes = df[change_col].astype(str).str.replace('%', '', regex=False)
        changes = changes.replace({'-': None, 'None': None, 'nan': None}).astype(float).dropna()
        if changes.empty:
            raise RuntimeError('no valid change pct rows')
        up = int((changes > 0).sum())
        down = int((changes < 0).sum())
        flat = int((changes == 0).sum())
        total = int(len(changes))
        ratio = float(up / total) if total > 0 else None
        return {
            "available": True,
            "source": "efinance.stock.get_realtime_quotes",
            "up_count": up, "down_count": down, "flat_count": flat,
            "total_count": total, "up_ratio": ratio,
        }
    except Exception as e:
        return {"available": False, "source": "efinance.stock.get_realtime_quotes", "error": repr(e)}


# ── 3. Tushare（降级兜底）───────────────────────────────────────────────────
def _load_tushare_token() -> str | None:
    """从多个位置加载 Tushare token。"""
    paths = [
        ROOT.parent / 'daily_stock_analysis' / '.env.tushare',
        ROOT / '.env.tushare',
        Path.home() / '.openclaw' / 'workspace' / 'quant_projects' / 'daily_stock_analysis' / '.env.tushare',
    ]
    for p in paths:
        if p.exists():
            for line in p.read_text().splitlines():
                if 'TUSHARE_TOKEN' in line or line.startswith('export '):
                    parts = line.strip().split('=')
                    if len(parts) == 2:
                        return parts[1].strip().strip("'\"")
    return None


def fetch_from_tushare(trade_date: str = "") -> dict[str, Any]:
    """通过 Tushare Pro 获取今日全市场日线数据，计算宽度。"""
    import tushare as ts

    token = _load_tushare_token()
    if not token:
        return {"available": False, "source": "tushare.daily", "error": "no_token"}
    pro = ts.pro_api(token)

    if not trade_date:
        from datetime import datetime
        trade_date = datetime.now().strftime('%Y%m%d')

    try:
        # 获取今日全市场日线（分批，每批100只）
        # 先拿股票列表
        df_list = pro.stock_basic(exchange='', list_status='L', fields='ts_code')
        all_codes = df_list['ts_code'].tolist()

        all_daily = []
        batch_size = 100
        rate_limited = False
        for i in range(0, min(len(all_codes), 5000), batch_size):
            batch = all_codes[i:i + batch_size]
            try:
                df = pro.daily(ts_code=','.join(batch), trade_date=trade_date)
                if df is not None and not df.empty:
                    all_daily.append(df[['ts_code', 'pct_chg']])
                time.sleep(0.2)
            except Exception as e:
                if '500' in str(e):
                    rate_limited = True
                    break
                time.sleep(0.5)

        if not all_daily:
            return {
                "available": False,
                "source": "tushare.daily",
                "error": "rate_limited" if rate_limited else "no_data_fetched",
            }

        import pandas as pd
        combined = pd.concat(all_daily, ignore_index=True)
        changes = combined['pct_chg'].dropna().astype(float)
        up = int((changes > 0).sum())
        down = int((changes < 0).sum())
        flat = int((changes == 0).sum())
        total = int(len(changes))
        ratio = float(up / total) if total > 0 else None
        return {
            "available": True,
            "source": "tushare.daily",
            "up_count": up, "down_count": down, "flat_count": flat,
            "total_count": total, "up_ratio": ratio,
            "note": f"降级数据源（AkShare/eFinance 不可用），基于 {len(combined)} 只股票",
        }
    except Exception as e:
        return {"available": False, "source": "tushare.daily", "error": repr(e)}


# ── 主入口 ─────────────────────────────────────────────────────────────────
def fetch_intraday_breadth(max_retry: int = 2, sleep_sec: float = 1.5) -> dict[str, Any]:
    """
    三源兜底：AkShare → eFinance → Tushare。
    当 1+2 被代理阻塞时，触发 Tushare 降级。
    """
    # 源1：AkShare
    ak = fetch_from_akshare(max_retry=max_retry, sleep_sec=sleep_sec)
    if ak.get('available'):
        return ak

    # 源2：eFinance
    ef = fetch_from_efinance()
    if ef.get('available'):
        return ef

    # 源3：Tushare（降级兜底）
    ts_result = fetch_from_tushare()
    if ts_result.get('available'):
        return ts_result

    return {
        "available": False,
        "source": "akshare|efinance|tushare",
        "error": {
            "akshare": ak.get('error'),
            "efinance": ef.get('error'),
            "tushare": ts_result.get('error'),
        },
    }


if __name__ == "__main__":
    result = fetch_intraday_breadth()
    print(json.dumps(result, ensure_ascii=False, indent=2))

