import subprocess
import sys
from datetime import datetime
from pathlib import Path
from typing import Any

import pandas as pd

PROJECT_ROOT = Path(__file__).resolve().parents[1]
SCRIPTS_DIR = PROJECT_ROOT / "scripts"
for candidate in [PROJECT_ROOT, SCRIPTS_DIR]:
    if str(candidate) not in sys.path:
        sys.path.insert(0, str(candidate))

from run_live_execution_v1 import (  # type: ignore
    A_STOCK_CSV,
    REPORT_DIR,
    apply_gray_policy,
    load_adv20_map,
    load_holdings_map,
    load_json,
    size_orders,
    write_orders,
)
from generate_paper_trading_dashboard import load_all_trade_rows  # type: ignore
from paper_profile_utils import (  # type: ignore
    account_glob,
    profile_name_from_config,
    profile_slug_from_config,
    report_path,
)
from prepare_live_signal_tickets import build_ticket_rows, write_ticket_rows  # type: ignore
from scripts.runtime_date_utils import (  # type: ignore
    evaluate_runtime_state_for_date,
    load_runtime_metrics_for_date,
)
