    EXECUTION_OVERLAY_PROFILE,
    apply_stock_analysis_overlay,
)
from scripts.intraday_market_gate import get_intraday_market_state

DEFAULT_CONFIG_PATH = PROJECT_ROOT / "config" / "paper_trading_aggressive_v1.json"
MERGED_SIGNALS_DIR = PROJECT_ROOT / "signals" / "merged"
DEFAULT_RISK_CONFIG_PATH = PROJECT_ROOT / "risk" / "configs" / "default_risk_config.json"


def parse_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(str(value).replace(",", "").strip())
    except Exception:
        return default


def parse_date_tag(value: str) -> str:
    text = str(value or "").strip()
    if re.fullmatch(r"\d{8}", text):
        return text
    if re.fullmatch(r"\d{4}-\d{2}-\d{2}", text):
        return text.replace("-", "")
    raise ValueError(f"无效日期: {value}")


def parse_optional_date_tag(value: Any) -> str:
    text = str(value or "").strip()
    if not text:
        return ""
    return parse_date_tag(text)


def tag_to_iso(tag: str) -> str:
    return f"{tag[0:4]}-{tag[4:6]}-{tag[6:8]}"


def resolve_path(path_like: str) -> Path:
    path = Path(str(path_like))
    if path.is_absolute():
        return path
    return (PROJECT_ROOT / path).resolve()


def latest_file_in_dir(directory: Path, pattern: str) -> Path:
    files = sorted(directory.glob(pattern))
    if not files:
        raise FileNotFoundError(f"未找到文件: {directory / pattern}")
    return files[-1]


def extract_date_tag(path: Path) -> str:
    match = re.search(r"(\d{8})", path.name)
    return match.group(1) if match else datetime.now().strftime("%Y%m%d")


def resolve_merged_signals_path(date_tag: str, merged_signals_arg: str = "") -> Path:
    if merged_signals_arg:
        path = resolve_path(merged_signals_arg)
        if not path.exists():
            raise FileNotFoundError(f"未找到指定 merged_signals 文件: {path}")
        return path
    dated = MERGED_SIGNALS_DIR / f"merged_signals_{date_tag}.csv"
    if dated.exists():
        return dated
    raise FileNotFoundError(f"缺少指定日期的 merged_signals 文件: {dated}")


def build_profile_artifact_paths(profile_slug: str, date_tag: str) -> dict[str, Path]:
    prefix = f"paper_{profile_slug}" if profile_slug else "paper"
    return {
        "holdings_input": REPORT_DIR / f"{prefix}_exit_holdings_{date_tag}.csv",
        "trade_history": REPORT_DIR / f"{prefix}_trade_history_{date_tag}.csv",
        "approved": REPORT_DIR / f"{prefix}_merged_approved_signals_{date_tag}.csv",
        "candidate_orders": REPORT_DIR / f"{prefix}_merged_proposed_orders_{date_tag}.csv",
        "tickets": REPORT_DIR / f"{prefix}_signal_tickets_{date_tag}.csv",
    }


def build_trade_history_frame(trades_df: pd.DataFrame) -> pd.DataFrame:
    if trades_df.empty:
        return pd.DataFrame(columns=["ts_code", "action", "date", "price", "shares"])
    out = pd.DataFrame()
    out["ts_code"] = trades_df.get("ts_code", pd.Series(dtype=str)).fillna("").astype(str).str.upper().str.strip()
    out["action"] = trades_df.get("action", pd.Series(dtype=str)).fillna("").astype(str).str.upper().str.strip()
    out["date"] = trades_df.get("date", pd.Series(dtype=str)).fillna("").astype(str).str.strip()
    out["price"] = pd.to_numeric(trades_df.get("price", pd.Series(dtype=float)), errors="coerce").fillna(0.0)
    out["shares"] = pd.to_numeric(trades_df.get("shares", pd.Series(dtype=float)), errors="coerce").fillna(0).astype(int)
    out = out[(out["ts_code"] != "") & (out["action"].isin(["BUY", "SELL"])) & (out["date"] != "")]
    return out.reset_index(drop=True)


def write_trade_history(path: Path, trades_df: pd.DataFrame) -> bool:
