#!/usr/bin/env python3
from __future__ import annotations

import argparse
import os
import subprocess
import sys
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
ORIGINAL = ROOT / 'scripts' / 'run_paper_trading_sim_v1.py'
GUARD = ROOT / 'scripts' / 'prewrite_paper_guard.py'
REPORT_DIR = ROOT / 'research' / 'reports'


def infer_profile_from_args(argv: list[str]) -> str:
    for i, arg in enumerate(argv):
        if arg in {'--profile', '--profile-slug'} and i + 1 < len(argv):
            raw = argv[i + 1].strip().lower()
            if 'defensive' in raw:
                return 'defensive'
            if 'balanced' in raw:
                return 'balanced'
            if 'aggressive' in raw:
                return 'aggressive'
    joined = ' '.join(argv).lower()
    for p in ['defensive', 'balanced', 'aggressive']:
        if p in joined:
            return p
    return 'balanced'


def infer_date_from_args(argv: list[str]) -> str:
    for i, arg in enumerate(argv):
        if arg == '--date' and i + 1 < len(argv):
            return argv[i + 1].replace('-', '')
    return os.popen('date +%Y%m%d').read().strip()


def main() -> None:
    passthrough = sys.argv[1:]
    profile = infer_profile_from_args(passthrough)
    date_tag = infer_date_from_args(passthrough)

    cmd = [sys.executable, str(ORIGINAL), *passthrough]
    res = subprocess.run(cmd, cwd=str(ROOT))
    if res.returncode != 0:
        raise SystemExit(res.returncode)

    account_json = REPORT_DIR / f'paper_{profile}_account_v1_{date_tag}.json'
    guard_cmd = [sys.executable, str(GUARD), '--date', date_tag, '--profile', profile, '--account-json', str(account_json)]
    guard = subprocess.run(guard_cmd, cwd=str(ROOT))
    if guard.returncode != 0:
        raise SystemExit(guard.returncode)


if __name__ == '__main__':
    main()

