    if raw.endswith(".XSHG") or raw.endswith(".XSHE"):
        return raw
    if raw.endswith(".SH"):
        return raw[:-3] + ".XSHG"
    if raw.endswith(".SZ"):
        return raw[:-3] + ".XSHE"
    if raw.startswith("SH") and len(raw) >= 8:
        return f"{raw[2:8]}.XSHG"
    if raw.startswith("SZ") and len(raw) >= 8:
        return f"{raw[2:8]}.XSHE"
    if raw.isdigit() and len(raw) == 6:
        market = "XSHG" if raw.startswith(("5", "6", "9")) else "XSHE"
        return f"{raw}.{market}"
    return raw


