    exact = REPORT_DIR / f"{pattern_prefix}_{date_tag}.{suffix}"
    if exact.exists():
        return exact
    candidates = sorted(REPORT_DIR.glob(f"{pattern_prefix}_*.{suffix}"))
    if not candidates:
        return None
    eligible = [path for path in candidates if path.stem.rsplit("_", 1)[-1] <= date_tag]
